{"code": "import json
import pandas as pd

# Get the file path from storage
file_path = locals().get('var_functions.query_db:12', '')

# Read the full results from the file
if file_path:
    try:
        with open(file_path, 'r') as f:
            books_data = json.load(f)

        # Create DataFrame to explore structure
        df_books = pd.DataFrame(books_data)

        # Extract book IDs and titles for Literature & Fiction category
        book_ids = df_books[['book_id', 'title']].to_dict('records')

        result = {
            'total_books': len(book_ids),
            'sample_books': book_ids[:5]
        }

        print('__RESULT__:')
        print(json.dumps(result))

    except Exception as e:
        error_result = {'error': str(e)}
        print('__RESULT__:')
        print(json.dumps(error_result))
else:
    error_result = {'error': 'No file path found'}
    print('__RESULT__:')
    print(json.dumps(error_result))"}

